import { z } from 'zod';

const envSchema = z.object({
  NODE_ENV: z.enum(['development', 'production', 'test']),
  PORT: z.string().regex(/^\d+$/),
  JWT_SECRET: z.string().min(32),
  TELEGRAM_BOT_TOKEN: z.string().min(1),
  CORS_WHITELIST: z.string().optional(),
  RATE_LIMIT_WINDOW_MS: z.string().regex(/^\d+$/),
  RATE_LIMIT_MAX: z.string().regex(/^\d+$/)
});

const _env = envSchema.safeParse(process.env);

if (!_env.success) {
  console.error('Environment variables validation failed!', _env.error.format());
  process.exit(1);
}

export const env = _env.data;

export const mapToNotificationMessage = (task) => {
  const assignee = task.assignees[task.rotationIndex];
  return `Task '${task.title}' is currently assigned to ${assignee}. Follow up as per the schedule.`;
};

import { Telegraf } from 'telegraf';
import { env } from '../../config/env';

class MessageRepository {
  private bot: Telegraf;

  constructor() {
    this.bot = new Telegraf(env.TELEGRAM_BOT_TOKEN);
  }

  async sendMessage(chatId: string, message: string): Promise<void> {
    try {
      await this.bot.telegram.sendMessage(chatId, message);
    } catch (error) {
      console.error('Error sending message:', error);
      throw new Error('Failed to send message');
    }
  }
}

export const messageRepository = new MessageRepository();

import { messageRepository } from '../repositories/message.repository';
import { GroupRepository } from '../../group/repositories/group.repository';
import { TaskRepository } from '../../task/repositories/task.repository';
import { mapToNotificationMessage } from '../mappers/telegraf-command.mapper';

class NotificationService {
  private groupRepo: GroupRepository;
  private taskRepo: TaskRepository;

  constructor(groupRepo: GroupRepository, taskRepo: TaskRepository) {
    this.groupRepo = groupRepo;
    this.taskRepo = taskRepo;
  }

  async dispatchNotifications(): Promise<void> {
    const tasks = await this.taskRepo.getActiveTasks();
    for (const task of tasks) {
      const group = await this.groupRepo.findById(task.groupId);
      if (!group.telegramChatId) {
        console.warn(
          `Cannot send notification for task ${task.id} without linked Telegram chat id.`
        );
        continue;
      }
      const message = mapToNotificationMessage(task);
      await messageRepository.sendMessage(group.telegramChatId, message);
    }
  }
}

export const notificationService = new NotificationService(new GroupRepository(), new TaskRepository());

import { Router } from 'express';
import { notificationService } from '../services/notification.service';

const router = Router();

router.post('/dispatch', async (req, res, next) => {
  try {
    await notificationService.dispatchNotifications();
    res.status(204).end();
  } catch (error) {
    next(error);
  }
});

export default router;

import express from 'express';
import helmet from 'helmet';
import cors from 'cors';
import rateLimit from 'express-rate-limit';
import notificationRouter from './modules/notification/controllers/notification.controller';
import { env } from './config/env';

const app = express();

// Security Middlewares
app.use(helmet());
app.use(cors({ origin: env.CORS_WHITELIST }));
app.use(
  rateLimit({
    windowMs: parseInt(env.RATE_LIMIT_WINDOW_MS, 10),
    max: parseInt(env.RATE_LIMIT_MAX, 10)
  })
);

app.use(express.json());

// Routes
app.use('/api/v1/notifications', notificationRouter);

// Error handling middleware
app.use((err, req, res, next) => {
  console.error(err);
  res.status(500).json({ error: 'Internal Server Error' });
});

export default app;

import app from './app';
import { env } from './config/env';

const PORT = parseInt(env.PORT, 10);

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
